%[text] # script to test out the GaN thermodynamic scenarios
conditions.T_equilibrium = 300:10:2000;
conditions.P_tot = 1;
conditions.P_units = 'atm';

conditions.X_GaN = 1;    % this is a solid so Xi=1
conditions.X_Ga = 1;     % set these as the default and change them if needed below

conditions.pN2 = 1;   
conditions.pH2 = 1;
conditions.pNH3 = 1;
%%
figure(1) %[output:01d13c59]
clf %[output:01d13c59]
hold on %[output:01d13c59]

conditions.T_dep_matrix_mu_flag = 'Off';
conditions.mu_GaN = -1.8;   %this is an arbitrary gues, not the real number.  This would be a constant that we get out of a computational paper for the enthalpy of formation for GaN
conditions.mu_conditions_flag = 'Ga-rich';
[mu_Ga, mu_N] = Ga_N2_GaN_chem_potentials_from_conditions(conditions); %[output:5572818e]

plot(conditions.T_equilibrium,mu_Ga,'b-') %[output:01d13c59]
plot(conditions.T_equilibrium,mu_N,'g-') %[output:01d13c59]

legend('\mu_{Ga} Ga-rich','\mu_{N} Ga-rich') %[output:01d13c59]
xlabel('T (K)') %[output:01d13c59]
ylabel('\mu (eV)') %[output:01d13c59]
ylim([-6 0]) %[output:01d13c59]
% saveas(gcf, 'Ga-rich.png');
%%
figure(2) %[output:41aaaa27]
clf %[output:41aaaa27]
hold on %[output:41aaaa27]

conditions.mu_conditions_flag = 'N-rich';
conditions.T_dep_matrix_mu_flag = 'Off';
conditions.mu_GaN = -1.8;   %this is an arbitrary gues, not the real number.  This would be a constant that we get out of a computational paper for the enthalpy of formation for GaN
[mu_Ga, mu_N] = Ga_N2_GaN_chem_potentials_from_conditions(conditions); %[output:0439a435]

plot(conditions.T_equilibrium,mu_Ga,'b-') %[output:41aaaa27]
plot(conditions.T_equilibrium,mu_N,'g-') %[output:41aaaa27]

legend('\mu_{Ga} N-rich','\mu_{N} N-rich') %[output:41aaaa27]
xlabel('T (K)') %[output:41aaaa27]
ylabel('\mu (eV)') %[output:41aaaa27]
ylim([-6 0]) %[output:41aaaa27]
% saveas(gcf, 'N-rich.png');
%%
figure(3) %[output:4e221a43]
clf %[output:4e221a43]
hold on %[output:4e221a43]

conditions.T_dep_matrix_mu_flag = 'On';
conditions.mu_conditions_flag = 'GaN_touching_Ga(l,s)';

[mu_Ga, mu_N] = Ga_N2_GaN_chem_potentials_from_conditions(conditions); %[output:0160d4fd]

plot(conditions.T_equilibrium,mu_Ga,'b-') %[output:4e221a43]
plot(conditions.T_equilibrium,mu_N,'g-') %[output:4e221a43]

legend('\mu_{Ga} GaN touching Ga(l,s)','\mu_{N} GaN touching Ga(l,s)','Location','south') %[output:4e221a43]
xlabel('T (K)') %[output:4e221a43]
ylabel('\mu (eV)') %[output:4e221a43]
ylim([-6 0]) %[output:4e221a43]
%%
figure(4)
clf %[output:4869c449]
hold on %[output:4869c449]

conditions.mu_conditions_flag = 'Ga_equilibrium_vapor_pressure_over_Ga_at_T';

[mu_Ga, mu_N] = Ga_N2_GaN_chem_potentials_from_conditions(conditions); %[output:6c8c8544]

plot(conditions.T_equilibrium,mu_Ga,'b-') %[output:4869c449]
plot(conditions.T_equilibrium,mu_N,'g-') %[output:4869c449]

legend('\mu_{Ga} Ga equilibrium vapor pressure over Ga at T','\mu_{N} Ga equilibrium vapor pressure over Ga at T', 'Location', 'south') %[output:4869c449]
xlabel('T (K)') %[output:4869c449]
ylabel('\mu (eV)') %[output:4869c449]
ylim([-6 0]) %[output:4869c449]
%%
figure(5)
clf
hold on


conditions.T_equilibrium = 300:10:2000;

conditions.mu_conditions_flag = 'pN2-variable';
conditions.P_tot = 1;
conditions.pN2 = 0.8;

conditions.pN2 = conditions.pN2/conditions.P_tot;   %this corresponds to air at 1 atm, or N2+Argon at 1 atm (note that our definition of thermodynamics of Ga-N system does not include reactive oxygen as of now  
% 
% %If we want to do pure N2 at 0.1 atm 
% conditions.P_tot=0.1;
% conditions.X_N2 = 1   %this corresponds to air at 1 atm.


[mu_Ga, mu_N] = Ga_N2_GaN_chem_potentials_from_conditions(conditions);

plot(conditions.T_equilibrium,mu_Ga,'b-')
plot(conditions.T_equilibrium,mu_N,'g-')

legend('\mu_{Ga} pN2-variable','\mu_{N} pN2-variable','Location','south')
xlabel('T (K)')
ylabel('\mu (eV)')
ylim([-6 0])

conditions.P_tot=1;   %
conditions.pN2 = 1;   %set these back to defaults beofre going on
%%
figure(6)
clf
hold on


conditions.mu_conditions_flag = 'N2-1atm';   %this condition definition will include setting X_N2 and Ptot both to 1.  


[mu_Ga, mu_N] = Ga_N2_GaN_chem_potentials_from_conditions(conditions);

plot(conditions.T_equilibrium,mu_Ga,'b-')
plot(conditions.T_equilibrium,mu_N,'g-')

legend('\mu_{Ga} N2-1atm','\mu_{N} N2-1atm','Location','south')
xlabel('T (K)')
ylabel('\mu (eV)')
ylim([-6 0])
%%
figure(7)
clf
hold on

conditions.mu_conditions_flag = 'air-1atm';  

[mu_Ga, mu_N] = Ga_N2_GaN_chem_potentials_from_conditions(conditions);

plot(conditions.T_equilibrium,mu_Ga,'b-')
plot(conditions.T_equilibrium,mu_N,'g-')

legend('\mu_{Ga} air-1atm','\mu_{N} air-1atm','Location','south')
xlabel('T (K)')
ylabel('\mu (eV)')
ylim([-6 0])
%%
figure(8)
clf
hold on

conditions.mu_conditions_flag = 'N2 determined from NH3/H2 Equilibrium';
conditions.P_tot = 0.01;   % this is a few Torr pressure
conditions.X_H2 = 0.1;   % these are the mol fractions of H2 and NH3 
conditions.X_NH3 = 0.9;

conditions.pH2 = conditions.P_tot * conditions.X_H2;   % these are the mol fractions of H2 and NH3 
conditions.pNH3 = conditions.P_tot * conditions.X_NH3; 

[mu_Ga, mu_N] = Ga_N2_GaN_chem_potentials_from_conditions(conditions);

plot(conditions.T_equilibrium,mu_Ga,'b-')
plot(conditions.T_equilibrium,mu_N,'g-')

legend('\mu_{Ga} N2 determined from NH3/H2 Equilibrium','\mu_{N} N2 determined from NH3/H2 Equilibrium')
xlabel('T (K)')
ylabel('\mu (eV)')
ylim([-6 0])

conditions.P_tot = 1;   % reset to defaults 
conditions.pH2 = 1;   
conditions.pNH3 = 1;
conditions.X_H2 = 1; 
conditions.X_NH3 = 1;


